option.value:
/* =========================================================
   Home Automation Server – Main Stylesheet
   ========================================================= */

:root {
    --bg: #0f0f12;
    --surface: #1a1a22;
    --surface2: #24242f;
    --border: #2e2e3e;
    --accent: #7c6af7;
    --accent-hover: #9d8fff;
    --success: #34d399;
    --danger: #f87171;
    --warning: #fbbf24;
    --text: #e2e2f0;
    --text-muted: #8888aa;
    --mono-font: "JetBrains Mono", "Fira Code", "Cascadia Code", monospace;
    --sans-font: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    --radius: 10px;
    --radius-sm: 6px;
    --shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; }

body {
    background: var(--bg);
    color: var(--text);
    font-family: var(--sans-font);
    line-height: 1.6;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

/* ── Header ── */
.site-header {
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    padding: 0 2rem;
    position: sticky;
    top: 0;
    z-index: 100;
}

.header-inner {
    max-width: 1200px;
    margin: 0 auto;
    height: 60px;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.logo {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--text);
    text-decoration: none;
    letter-spacing: -0.5px;
}

nav { display: flex; gap: 1.5rem; }

nav a {
    color: var(--text-muted);
    text-decoration: none;
    font-size: 0.9rem;
    transition: color 0.15s;
}

nav a:hover { color: var(--accent-hover); }

/* ── Main container ── */
.container {
    max-width: 1200px;
    margin: 2rem auto;
    padding: 0 2rem;
    flex: 1;
    width: 100%;
}

/* ── Footer ── */
.site-footer {
    text-align: center;
    padding: 1.5rem;
    font-size: 0.8rem;
    color: var(--text-muted);
    border-top: 1px solid var(--border);
    margin-top: 3rem;
}

/* ── Page header ── */
.page-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 1.5rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid var(--border);
}

.page-header h1 { font-size: 1.75rem; font-weight: 700; }

/* ── Hero (index) ── */
.hero { margin-bottom: 2.5rem; }
.hero h1 { font-size: 2.2rem; font-weight: 800; margin-bottom: 0.5rem; }
.subtitle { color: var(--text-muted); font-size: 1.1rem; }

/* ── Card grid ── */
.card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 1.25rem;
    margin-bottom: 2rem;
}

.card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1.5rem;
    text-decoration: none;
    color: var(--text);
    transition: border-color 0.15s, transform 0.15s;
    display: block;
}

.card:hover {
    border-color: var(--accent);
    transform: translateY(-2px);
}

.card-icon { font-size: 2rem; display: block; margin-bottom: 0.75rem; }
.card h2 { font-size: 1.1rem; margin-bottom: 0.25rem; }
.card p { font-size: 0.85rem; color: var(--text-muted); }

/* ── Card form ── */
.card-form {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1.5rem;
    margin-bottom: 1.5rem;
}

.card-form h2 { margin-bottom: 1rem; font-size: 1.15rem; }

/* ── Forms ── */
.form {
    display: flex;
    flex-direction: column;
    gap: 0.85rem;
}

.form label {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    font-size: 0.875rem;
    color: var(--text-muted);
}

.form input,
.form select,
.form textarea {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    color: var(--text);
    font-size: 0.95rem;
    font-family: var(--sans-font);
    padding: 0.55rem 0.75rem;
    transition: border-color 0.15s;
    width: 100%;
}

.form input:focus,
.form select:focus,
.form textarea:focus {
    outline: none;
    border-color: var(--accent);
}

/* ── Buttons ── */
.btn {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    border: none;
    border-radius: var(--radius-sm);
    cursor: pointer;
    font-size: 0.9rem;
    font-weight: 500;
    padding: 0.55rem 1.1rem;
    transition: opacity 0.15s, transform 0.1s;
    text-decoration: none;
}

.btn:hover { opacity: 0.88; transform: translateY(-1px); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary  { background: var(--accent);  color: #fff; }
.btn-success  { background: var(--success); color: #000; }
.btn-danger   { background: var(--danger);  color: #000; }
.btn-secondary{ background: var(--surface2); color: var(--text); border: 1px solid var(--border); }

.btn-sm { font-size: 0.8rem; padding: 0.3rem 0.7rem; }

/* ── Tables ── */
.data-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.data-table th,
.data-table td {
    text-align: left;
    padding: 0.65rem 1rem;
    border-bottom: 1px solid var(--border);
}

.data-table th {
    background: var(--surface2);
    color: var(--text-muted);
    font-weight: 600;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.data-table tr:hover td { background: var(--surface2); }

/* ── Badges ── */
.badge {
    display: inline-block;
    padding: 0.2rem 0.55rem;
    border-radius: 999px;
    font-size: 0.75rem;
    font-weight: 600;
    background: var(--surface2);
    color: var(--text-muted);
    border: 1px solid var(--border);
}

.badge-trigger { background: rgba(124,106,247,0.2); color: var(--accent-hover); border-color: var(--accent); }
.badge-action  { background: rgba(52,211,153,0.15); color: var(--success); border-color: var(--success); }

/* ── Notices ── */
.notice {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.85rem 1rem;
    font-size: 0.9rem;
    color: var(--text-muted);
    margin: 0.75rem 0;
}

.notice a { color: var(--accent-hover); }

/* ── Collapsible ── */
.collapsible {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    margin-bottom: 1.5rem;
}

.collapsible summary {
    cursor: pointer;
    padding: 1rem 1.25rem;
    font-weight: 600;
    user-select: none;
    list-style: none;
}

.collapsible summary::-webkit-details-marker { display: none; }

.collapsible .form,
.collapsible > form {
    padding: 0 1.25rem 1.25rem;
}

/* ── Scan card ── */
.scan-card {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.85rem 1rem;
    margin-bottom: 0.6rem;
    display: flex;
    align-items: center;
    gap: 0.75rem;
    flex-wrap: wrap;
}

/* ── Credential block ── */
.credential-block {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
}

.credential-block h3 {
    margin-bottom: 0.75rem;
    font-size: 1rem;
    color: var(--text-muted);
}

/* ── Utility ── */
.mono { font-family: var(--mono-font); font-size: 0.82rem; }
.truncate { max-width: 280px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.hidden { display: none !important; }

.webhook-url {
    font-size: 0.75rem;
    color: var(--text-muted);
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 0.15rem 0.45rem;
}

/* ── Controls page ── */
.controls-error-banner {
    position: fixed;
    top: 78px;
    left: 50%;
    transform: translateX(-50%);
    width: min(920px, calc(100vw - 2rem));
    z-index: 1200;
    border-color: var(--danger);
    color: var(--danger);
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.75rem;
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.35);
}

.controls-direction-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(70px, 90px));
    gap: 0.5rem;
    align-items: center;
    justify-content: start;
}

.controls-button-row {
    display: flex;
    gap: 0.6rem;
    flex-wrap: wrap;
}

.controls-power-state-row {
    margin-top: 0.75rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.controls-apps-header {
    margin-bottom: 1rem;
}

.controls-apps-results {
    margin-top: 1rem;
}

/* ── Automation builder ── */
.automation-builder {
    display: grid;
    grid-template-columns: minmax(220px, 280px) 1fr;
    gap: 1rem;
    align-items: start;
}

.automation-palette,
.automation-sequence {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.9rem;
}

.automation-palette h3,
.automation-sequence h3 {
    margin-bottom: 0.25rem;
    font-size: 1rem;
}

.palette-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
    border: 1px dashed var(--border);
    border-radius: var(--radius-sm);
    padding: 0.55rem 0.6rem;
    margin-bottom: 0.5rem;
    background: var(--surface);
    cursor: grab;
}

.palette-item:active {
    cursor: grabbing;
}

.sequence-step {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.7rem;
    margin-bottom: 0.6rem;
}

.sequence-step-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

/* ── Responsive ── */
@media (max-width: 640px) {
    .header-inner { flex-direction: column; height: auto; padding: 0.75rem 0; gap: 0.5rem; }
    nav { gap: 0.85rem; flex-wrap: wrap; justify-content: center; }
    .container { padding: 0 1rem; margin: 1rem auto; }
    .page-header { flex-direction: column; align-items: flex-start; gap: 0.75rem; }
    .card-grid { grid-template-columns: 1fr 1fr; }
    .automation-builder { grid-template-columns: 1fr; }
}

