    padding: 1rem;
    margin-bottom: 0.75rem;
}

.device-card-header {
    margin-bottom: 0.75rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid var(--border);
}

.device-card-header h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--text);
}

.device-card-body {
    margin-bottom: 0.75rem;
}

.device-info-row {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    align-items: flex-start;
}

.device-label {
    font-size: 0.8rem;
    color: var(--text-muted);
    font-weight: 600;
    min-width: 70px;
}

.device-value {
    font-size: 0.85rem;
    color: var(--text);
    word-break: break-all;
    flex: 1;
}

.device-badges {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

.device-card-actions {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
}

/* Device cards for mobile */
.devices-card-grid { display: none; }
.data-table-desktop { display: table; }

