.automation-builder {
    display: grid;
    grid-template-columns: minmax(220px, 280px) 1fr;
    gap: 1rem;
    align-items: start;
}

.automation-palette,
.automation-sequence {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.9rem;
}

.automation-palette h3,
.automation-sequence h3 {
    margin-bottom: 0.25rem;
    font-size: 1rem;
}

.palette-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
    border: 1px dashed var(--border);
    border-radius: var(--radius-sm);
    padding: 0.55rem 0.6rem;
    margin-bottom: 0.5rem;
    background: var(--surface);
    cursor: grab;
}

.palette-item:active {
    cursor: grabbing;
}

.sequence-step {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 0.7rem;
    margin-bottom: 0.6rem;
}

.sequence-step-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 0.5rem;
}

/* ── Responsive ── */

/* Tablet (640px - 1023px) */
@media (max-width: 1023px) {
    html { font-size: 15px; }
    .container { padding: 0 1.5rem; margin: 1.5rem auto; }
    .card-grid { grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); }
    .automation-builder { grid-template-columns: 1fr; gap: 1.5rem; }
    .automation-palette { margin-bottom: 0.5rem; }
}

/* Mobile (max 640px) */
@media (max-width: 640px) {
    html { font-size: 14px; }

    /* Header adjustments */
    .site-header { padding: 0 1rem; }
    .header-inner {
        flex-direction: column;
        height: auto;
        padding: 0.75rem 0;
        gap: 0.5rem;
    }
    .logo { font-size: 1.1rem; }

    /* Navigation */
    nav {
        gap: 0.6rem;
        flex-wrap: wrap;
        justify-content: center;
    }
    nav a { font-size: 0.8rem; }

    /* Container & spacing */
    .container { padding: 0 1rem; margin: 1rem auto; }
    .page-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.75rem;
    }
    .page-header h1 { font-size: 1.5rem; }

    /* Hero */
    .hero h1 { font-size: 1.8rem; }
    .subtitle { font-size: 0.95rem; }

    /* Card grid */
    .card-grid { grid-template-columns: 1fr; }
    .card { padding: 1.25rem; }
    .card-icon { font-size: 1.75rem; }
    .card h2 { font-size: 1rem; }

    /* Forms & inputs (touch-friendly) */
    .form label { font-size: 0.8rem; }
    .form input,
    .form select,
    .form textarea {
        font-size: 1rem; /* Prevent zoom on iOS */
        padding: 0.7rem;
        min-height: 44px; /* Touch target minimum */
    }

    /* Tables – horizontal scroll on mobile */
    .data-table {
        font-size: 0.8rem;
        display: none;
    }
    .data-table-desktop {
        display: none !important;
    }
    .devices-card-grid {
        display: block;
    }

    /* Buttons – touch-friendly sizing */
    .btn {
        font-size: 0.85rem;
        padding: 0.65rem 1rem;
        min-height: 44px;
        min-width: 44px;
    }
    .btn-sm { padding: 0.4rem 0.6rem; min-height: 36px; }

    /* Controls */
    .controls-direction-grid {
        grid-template-columns: repeat(3, 1fr);
        gap: 0.4rem;
    }
    .controls-button-row {
        gap: 0.4rem;
        flex-direction: column;
        align-items: stretch;
    }
    .controls-button-row .btn { width: 100%; }
    .controls-power-state-row {
        flex-direction: column;
        align-items: stretch;
        gap: 0.4rem;
    }
    .controls-error-banner {
        width: calc(100vw - 1rem);
        flex-direction: column;
        gap: 0.5rem;
        padding: 0.75rem;
    }

    /* Automation builder */
    .automation-builder {
        grid-template-columns: 1fr;
        gap: 1rem;
    }
    .automation-palette,
    .automation-sequence {
        padding: 0.75rem;
    }
    .palette-item {
        flex-direction: column;
        gap: 0.4rem;
    }
    .palette-item span,
    .palette-item button {
        width: 100%;
        text-align: center;
    }
    .sequence-step {
        padding: 0.6rem;
    }
    .sequence-step-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 0.4rem;
    }
    .sequence-step-header strong { word-break: break-word; }

    /* Collapsible */
    .collapsible summary {
        padding: 0.85rem 1rem;
        font-size: 0.95rem;
    }
    .collapsible .form,
    .collapsible > form {
        padding: 0 1rem 1rem;
    }

    /* Badges */
    .badge { font-size: 0.7rem; padding: 0.15rem 0.4rem; }

    /* Utilities */
    .truncate { max-width: 100%; }
    .mono { font-size: 0.75rem; }
    .webhook-url {
        font-size: 0.7rem;
        max-width: 100%;
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        display: inline-block;
        word-break: break-all;
        max-height: 2.5rem;
        padding: 0.25rem 0.4rem;
        overflow-y: hidden;
    }

    /* Footer */
    .site-footer { padding: 1rem; font-size: 0.75rem; }
}

/* Ultra-mobile (max 380px) */
@media (max-width: 380px) {
    html { font-size: 13px; }
    .page-header h1 { font-size: 1.3rem; }
    .hero h1 { font-size: 1.5rem; }
    .btn, .btn-sm { padding: 0.6rem 0.8rem; }
    .controls-direction-grid { grid-template-columns: repeat(2, 1fr); }
}

{% extends "base.html" %}
{% block title %}Automations · Home Automation Server{% endblock %}

{% block content %}
<div class="page-header">
    <h1>Automation Flows</h1>
</div>

{% if not devices %}
<div class="notice">No devices saved. <a href="/ui/devices">Add a device first.</a></div>
{% else %}

<!-- Create flow form -->
<details class="collapsible" open>
    <summary>➕ Create New Flow</summary>
    <form class="form" onsubmit="createFlow(event)">
        <label>Name <input type="text" id="flow-name" required placeholder="Open Netflix on startup" /></label>
        <label>Device
            <select id="flow-device-id" onchange="onDeviceChanged()">
                {% for device in devices %}
                <option value="{{ device.id }}">{{ device.name }}</option>
                {% endfor %}
            </select>
        </label>
        <label>Trigger Type
            <select id="flow-trigger-type">
                <option value="webhook">Webhook</option>
                <option value="manual">Manual</option>
                <option value="schedule">Schedule</option>
            </select>
        </label>
        <label>Trigger Payload (JSON) <input type="text" id="flow-trigger-payload" value="{}" /></label>

        <div class="notice" id="flow-builder-status" style="display:none;"></div>

        <input type="hidden" id="editing-flow-id" value="" />

        <div class="automation-builder">
            <div class="automation-palette">
                <h3>Action Palette</h3>
                <p class="subtitle">Drag actions into the sequence or click add.</p>

                <div class="palette-item" draggable="true" data-action-kind="power_on" ondragstart="onPaletteDragStart(event)">
                    <span>⚡ Power On</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('power_on')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="power_off" ondragstart="onPaletteDragStart(event)">
                    <span> Power Off</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('power_off')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="launch_app" ondragstart="onPaletteDragStart(event)">
                    <span> Launch App</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('launch_app')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="remote_command" ondragstart="onPaletteDragStart(event)">
                    <span> Remote Command</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('remote_command')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="wait_seconds" ondragstart="onPaletteDragStart(event)">
                    <span>⏱ Wait</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('wait_seconds')">Add</button>
                </div>

                <button type="button" class="btn btn-secondary" onclick="loadAppsForDevice(true)"> Refresh App List</button>
            </div>

            <div class="automation-sequence" id="flow-dropzone" ondragover="onDropzoneDragOver(event)" ondrop="onDropzoneDrop(event)">
                <h3>Sequence</h3>
                <p class="subtitle">Drop actions here. Steps execute top → bottom.</p>
                <div id="flow-steps"></div>
            </div>
        </div>

        <div class="controls-button-row">
            <button type="submit" id="save-flow-btn" class="btn btn-primary">Save Flow</button>
            <button type="button" id="cancel-edit-btn" class="btn btn-secondary hidden" onclick="cancelEditMode()">Cancel Edit</button>
        </div>
    </form>
</details>

<!-- Flow list -->
<h2 style="margin-top:2rem;">Saved Flows</h2>
{% if flows %}
<table class="data-table">
    <thead>
        <tr>
            <th>Name</th>
            <th>Device</th>
            <th>Trigger</th>
            <th>Action</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
    {% for flow in flows %}
        <tr>
            <td>{{ flow.name }}</td>
            <td>{{ device_map[flow.device_id].name if flow.device_id in device_map else '–' }}</td>
            <td><span class="badge badge-trigger">{{ flow.trigger_type }}</span></td>
            <td><span class="badge badge-action">{{ flow.action_type }}</span></td>
            <td>
                <button class="btn btn-sm btn-primary" onclick="editFlow({{ flow.id }})">✏ Edit</button>
                <button class="btn btn-sm btn-success" onclick="runFlow({{ flow.id }})">▶ Run</button>
                <button class="btn btn-sm btn-danger" onclick="deleteFlow({{ flow.id }})">Delete</button>
                {% if flow.trigger_type == 'webhook' %}
                <span class="mono webhook-url" title="POST to this URL">/webhooks/trigger/{{ flow.id }}</span>
                {% endif %}
            </td>
        </tr>
    {% endfor %}
    </tbody>
</table>
{% else %}
<div class="notice">No automation flows yet. Create one above.</div>
{% endif %}
{% endif %}
{% endblock %}

{% block scripts %}
<script>
let steps = [];
let nextStepId = 1;
let cachedApps = [];

const REMOTE_COMMAND_OPTIONS = [
    'menu', 'top_menu', 'home', 'home_hold',
    'up', 'down', 'left', 'right', 'select',
    'play_pause', 'play', 'pause', 'stop', 'next', 'previous',
    'volume_up', 'volume_down'
];

function getEditingFlowId() {
    const raw = document.getElementById('editing-flow-id').value;
    const id = parseInt(raw, 10);
    return Number.isNaN(id) ? null : id;
}

function setEditingFlowId(idOrNull) {
    const hidden = document.getElementById('editing-flow-id');
    if (hidden) hidden.value = idOrNull == null ? '' : String(idOrNull);
}

function setEditMode(enabled) {
    const saveBtn = document.getElementById('save-flow-btn');
    const cancelBtn = document.getElementById('cancel-edit-btn');
    if (saveBtn) saveBtn.textContent = enabled ? 'Update Flow' : 'Save Flow';
    if (cancelBtn) cancelBtn.classList.toggle('hidden', !enabled);
}

function setBuilderStatus(message, isError = false) {
    const box = document.getElementById('flow-builder-status');
    if (!box) return;
    if (!message) {
        box.style.display = 'none';
        box.textContent = '';
        box.style.borderColor = '';
        box.style.color = '';
        return;
    }
    box.style.display = 'block';
    box.textContent = (isError ? '❌ ' : '✅ ') + message;
    if (isError) {
        box.style.borderColor = 'var(--danger)';
        box.style.color = 'var(--danger)';
    } else {
        box.style.borderColor = 'var(--success)';
        box.style.color = 'var(--success)';
    }
}

function stepTemplate(kind) {
    switch (kind) {
        case 'power_on':
            return { id: nextStepId++, type: 'power', payload: { turn_on: true } };
        case 'power_off':
            return { id: nextStepId++, type: 'power', payload: { turn_on: false } };
        case 'launch_app': {
            const bundleId = cachedApps.length > 0 ? (cachedApps[0].bundle_id || '') : '';
            return { id: nextStepId++, type: 'launch_app', payload: { bundle_id: bundleId } };
        }
        case 'remote_command':
            return { id: nextStepId++, type: 'remote_command', payload: { command: 'menu' } };
        case 'wait_seconds':
            return { id: nextStepId++, type: 'wait_seconds', payload: { seconds: 1 } };
        default:
            return null;
    }
}

function addStep(kind) {
    const step = stepTemplate(kind);
    if (!step) return;
    steps.push(step);
    renderSteps();
}

function removeStep(stepId) {
    steps = steps.filter(s => s.id !== stepId);
    renderSteps();
}

function duplicateStep(stepId) {
    const src = steps.find(s => s.id === stepId);
    if (!src) return;
    const copy = {
        id: nextStepId++,
        type: src.type,
        payload: JSON.parse(JSON.stringify(src.payload || {})),
    };
    const idx = steps.findIndex(s => s.id === stepId);
    steps.splice(idx + 1, 0, copy);
    renderSteps();
}

function moveStep(fromIndex, toIndex) {
    if (fromIndex === toIndex || fromIndex < 0 || toIndex < 0) return;
    const [item] = steps.splice(fromIndex, 1);
    steps.splice(toIndex, 0, item);
    renderSteps();
}

function onPaletteDragStart(event) {
    event.dataTransfer.setData('text/action-kind', event.currentTarget.dataset.actionKind);
}

function onStepDragStart(event) {
    event.dataTransfer.setData('text/step-index', event.currentTarget.dataset.index);
}

function onStepDragOver(event) {
    event.preventDefault();
}

function onStepDrop(event) {
    event.preventDefault();
    const from = parseInt(event.dataTransfer.getData('text/step-index'), 10);
    const to = parseInt(event.currentTarget.dataset.index, 10);
    if (!Number.isNaN(from) && !Number.isNaN(to)) {
        moveStep(from, to);
    }
}

function onDropzoneDragOver(event) {
    event.preventDefault();
}

function onDropzoneDrop(event) {
    event.preventDefault();
    const kind = event.dataTransfer.getData('text/action-kind');
    if (kind) {
        addStep(kind);
    }
}

function renderLaunchAppEditor(step, index) {
    const options = cachedApps.map(a => {
        const selected = a.bundle_id === step.payload.bundle_id ? 'selected' : '';
        return `<option value="${escapeHtml(a.bundle_id || '')}" ${selected}>${escapeHtml(a.name || 'Unknown')} (${escapeHtml(a.bundle_id || '')})</option>`;
    }).join('');

    const hasApps = cachedApps.length > 0;
    return `
        <label>App
            <select ${hasApps ? '' : 'disabled'} data-step-index="${index}" onchange="onLaunchAppSelected(event)">
                ${hasApps ? options : '<option value="">No apps available from device</option>'}
            </select>
        </label>
        <label>Bundle ID
            <input type="text" value="${escapeHtml(step.payload.bundle_id || '')}" data-step-index="${index}" oninput="onLaunchBundleInput(event)" placeholder="com.netflix.Netflix" />
        </label>
    `;
}

function renderPowerEditor(step, index) {
    const turnOn = !!step.payload.turn_on;
    return `
        <label>Power Action
            <select data-step-index="${index}" onchange="onPowerSelect(event)">
                <option value="on" ${turnOn ? 'selected' : ''}>Power On</option>
                <option value="off" ${!turnOn ? 'selected' : ''}>Power Off</option>
            </select>
        </label>
    `;
}

function renderRemoteEditor(step, index) {
    const options = REMOTE_COMMAND_OPTIONS.map(cmd => {
        const selected = cmd === step.payload.command ? 'selected' : '';
        return `<option value="${cmd}" ${selected}>${cmd}</option>`;
    }).join('');
    return `
        <label>Command
            <select data-step-index="${index}" onchange="onRemoteCommandSelect(event)">
                ${options}
            </select>
        </label>
    `;
}

function renderWaitEditor(step, index) {
    const seconds = Number(step.payload.seconds ?? 1);
    return `
        <label>Seconds
            <input type="number" min="0" step="0.1" value="${Number.isFinite(seconds) ? seconds : 1}" data-step-index="${index}" oninput="onWaitSecondsInput(event)" />
        </label>
    `;
}

function renderSteps() {
    const container = document.getElementById('flow-steps');
    if (!container) return;

    if (steps.length === 0) {
        container.innerHTML = '<div class="notice">No steps yet. Drag an action from the palette to begin.</div>';
        return;
    }

    container.innerHTML = steps.map((step, index) => {
        let editor = '';
        if (step.type === 'launch_app') editor = renderLaunchAppEditor(step, index);
        if (step.type === 'power') editor = renderPowerEditor(step, index);
        if (step.type === 'remote_command') editor = renderRemoteEditor(step, index);
        if (step.type === 'wait_seconds') editor = renderWaitEditor(step, index);

        return `
            <div class="sequence-step" draggable="true" data-index="${index}" ondragstart="onStepDragStart(event)" ondragover="onStepDragOver(event)" ondrop="onStepDrop(event)">
                <div class="sequence-step-header">
                    <strong>Step ${index + 1}: ${escapeHtml(step.type)}</strong>
                    <div class="controls-button-row">
                        <button type="button" class="btn btn-sm btn-secondary" onclick="duplicateStep(${step.id})">Duplicate</button>
                        <button type="button" class="btn btn-sm btn-danger" onclick="removeStep(${step.id})">Remove</button>
                    </div>
                </div>
                <div class="form" style="margin-top:0.5rem;">
                    ${editor}
                </div>
            </div>
        `;
    }).join('');
}

function onPowerSelect(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.turn_on = event.currentTarget.value === 'on';
}

function onRemoteCommandSelect(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.command = event.currentTarget.value;
}

function onWaitSecondsInput(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    const value = parseFloat(event.currentTarget.value);
    steps[idx].payload.seconds = Number.isNaN(value) ? 0 : Math.max(0, value);
}

function onLaunchAppSelected(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.bundle_id = event.currentTarget.value;
    renderSteps();
}

function onLaunchBundleInput(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.bundle_id = event.currentTarget.value.trim();
}

async function loadAppsForDevice(showStatus = false) {
    const deviceId = parseInt(document.getElementById('flow-device-id').value, 10);
    if (Number.isNaN(deviceId)) return;
    try {
        const res = await fetch(`/apps/list/${deviceId}`);
        const data = await res.json();
        if (!res.ok) {
            cachedApps = [];
            renderSteps();
            if (showStatus) {
                setBuilderStatus(data.detail || 'Could not load apps from device', true);
            }
            return;
        }

        cachedApps = Array.isArray(data) ? data : [];
        if (showStatus) {
            setBuilderStatus(`Loaded ${cachedApps.length} app(s) for selected device.`, false);
        }
        renderSteps();
    } catch (err) {
        cachedApps = [];
        renderSteps();
        if (showStatus) {
            setBuilderStatus(String(err), true);
        }
    }
}

async function onDeviceChanged() {
    await loadAppsForDevice(true);
}

function resetBuilderForNewFlow() {
    setEditingFlowId(null);
    setEditMode(false);
    steps = [];
    renderSteps();
}

function cancelEditMode() {
    resetBuilderForNewFlow();
    setBuilderStatus('Edit canceled. Creating new flow.', false);
}

function flowToSteps(flow) {
    let payload = {};
    try {
        payload = JSON.parse(flow.action_payload || '{}');
    } catch {
        payload = {};
    }

    if (flow.action_type === 'sequence' && Array.isArray(payload.actions)) {
        return payload.actions
            .filter(a => a && typeof a === 'object')
            .map(a => ({
                id: nextStepId++,
                type: String(a.type || a.action_type || ''),
                payload: (a.payload && typeof a.payload === 'object') ? a.payload : {},
            }))
            .filter(s => !!s.type);
    }

    // Backward compatibility: load legacy single-action flow as one visual step.
    return [{
        id: nextStepId++,
        type: String(flow.action_type || 'remote_command'),
        payload: payload && typeof payload === 'object' ? payload : {},
    }];
}

async function editFlow(flowId) {
    try {
        const res = await fetch(`/automations/${flowId}`);
        const flow = await res.json();
        if (!res.ok) {
            setBuilderStatus(flow.detail || 'Failed to load flow for editing.', true);
            return;
        }

        document.getElementById('flow-name').value = flow.name || '';
        document.getElementById('flow-device-id').value = String(flow.device_id);
        document.getElementById('flow-trigger-type').value = flow.trigger_type || 'manual';
        document.getElementById('flow-trigger-payload').value = flow.trigger_payload || '{}';

        await loadAppsForDevice(false);

        steps = flowToSteps(flow);
        renderSteps();
        setEditingFlowId(flowId);
        setEditMode(true);
        setBuilderStatus(`Editing flow: ${flow.name}`, false);

        // Scroll to top so editor is visible immediately
        window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
        setBuilderStatus(String(err), true);
    }
}

async function createFlow(e) {
    e.preventDefault();

    if (steps.length === 0) {
        setBuilderStatus('Add at least one step to the sequence.', true);
        return;
    }

    const sequencePayload = {
        actions: steps.map(step => ({
            type: step.type,
            payload: step.payload,
        }))
    };

    const editingId = getEditingFlowId();
    const endpoint = editingId ? `/automations/${editingId}` : '/automations/';
    const method = editingId ? 'PUT' : 'POST';

    const res = await fetch(endpoint, {
        method,
        headers: {'Content-Type':'application/json'},
        body: JSON.stringify({
            name: document.getElementById('flow-name').value,
            device_id: parseInt(document.getElementById('flow-device-id').value),
            trigger_type: document.getElementById('flow-trigger-type').value,
            trigger_payload: document.getElementById('flow-trigger-payload').value,
            action_type: 'sequence',
            action_payload: JSON.stringify(sequencePayload),
        })
    });

    if (res.ok) {
        location.reload();
    } else {
        const data = await res.json().catch(() => ({}));
        setBuilderStatus(data.detail || `Failed to ${editingId ? 'update' : 'create'} automation flow.`, true);
    }
}

document.addEventListener('DOMContentLoaded', () => {
    setEditMode(false);
    renderSteps();
    loadAppsForDevice(false);
});

async function runFlow(id) {
    const res = await fetch(`/automations/${id}/run`, { method: 'POST' });
    const data = await res.json();
    alert(res.ok ? '✅ Flow triggered: ' + JSON.stringify(data.action || data) : '❌ ' + (data.detail || 'Error'));
}

async function deleteFlow(id) {
    if (!confirm('Delete this flow?')) return;
    await fetch(`/automations/${id}`, { method: 'DELETE' });
    location.reload();
}

function escapeHtml(value) {
    return String(value)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Automations · Home Automation Server{% endblock %}

{% block content %}
<div class="page-header">
    <h1>Automation Flows</h1>
</div>

{% if not devices %}
<div class="notice">No devices saved. <a href="/ui/devices">Add a device first.</a></div>
{% else %}

<!-- Create flow form -->
<details class="collapsible" open>
    <summary>➕ Create New Flow</summary>
    <form class="form" onsubmit="createFlow(event)">
        <label>Name <input type="text" id="flow-name" required placeholder="Open Netflix on startup" /></label>
        <label>Device
            <select id="flow-device-id" onchange="onDeviceChanged()">
                {% for device in devices %}
                <option value="{{ device.id }}">{{ device.name }}</option>
                {% endfor %}
            </select>
        </label>
        <label>Trigger Type
            <select id="flow-trigger-type">
                <option value="webhook">Webhook</option>
                <option value="manual">Manual</option>
                <option value="schedule" disabled>Schedule (coming soon)</option>
            </select>
        </label>

        <div class="notice" id="flow-builder-status" style="display:none;"></div>

        <input type="hidden" id="editing-flow-id" value="" />

        <div class="automation-builder">
            <div class="automation-palette">
                <h3>Action Palette</h3>
                <p class="subtitle">Drag actions into the sequence or click add.</p>

                <div class="palette-item" draggable="true" data-action-kind="power_on" ondragstart="onPaletteDragStart(event)">
                    <span>⚡ Power On</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('power_on')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="power_off" ondragstart="onPaletteDragStart(event)">
                    <span> Power Off</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('power_off')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="launch_app" ondragstart="onPaletteDragStart(event)">
                    <span> Launch App</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('launch_app')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="remote_command" ondragstart="onPaletteDragStart(event)">
                    <span> Remote Command</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('remote_command')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="wait_seconds" ondragstart="onPaletteDragStart(event)">
                    <span>⏱ Wait</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('wait_seconds')">Add</button>
                </div>

                <div class="palette-item" draggable="true" data-action-kind="swipe" ondragstart="onPaletteDragStart(event)">
                    <span> Swipe</span>
                    <button type="button" class="btn btn-sm btn-secondary" onclick="addStep('swipe')">Add</button>
                </div>

                <button type="button" class="btn btn-secondary" onclick="loadAppsForDevice(true)"> Refresh App List</button>
            </div>

            <div class="automation-sequence" id="flow-dropzone" ondragover="onDropzoneDragOver(event)" ondrop="onDropzoneDrop(event)">
                <h3>Sequence</h3>
                <p class="subtitle">Drop actions here. Steps execute top → bottom.</p>
                <div id="flow-steps"></div>
            </div>
        </div>

        <div class="controls-button-row">
            <button type="submit" id="save-flow-btn" class="btn btn-primary">Save Flow</button>
            <button type="button" id="cancel-edit-btn" class="btn btn-secondary hidden" onclick="cancelEditMode()">Cancel Edit</button>
        </div>
    </form>
</details>

<!-- Flow list -->
<h2 style="margin-top:2rem;">Saved Flows</h2>
{% if flows %}
<table class="data-table">
    <thead>
        <tr>
            <th>Name</th>
            <th>Device</th>
            <th>Trigger</th>
            <th>Action</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
    {% for flow in flows %}
        <tr>
            <td>{{ flow.name }}</td>
            <td>{{ device_map[flow.device_id].name if flow.device_id in device_map else '–' }}</td>
            <td><span class="badge badge-trigger">{{ flow.trigger_type }}</span></td>
            <td><span class="badge badge-action">{{ flow.action_type }}</span></td>
            <td>
                <div style="display:flex;gap:0.4rem;flex-wrap:wrap;align-items:center;">
                    <button class="btn btn-sm btn-primary" onclick="editFlow({{ flow.id }})">✏ Edit</button>
                    <button class="btn btn-sm btn-success" onclick="runFlow({{ flow.id }})">▶ Run</button>
                    <button class="btn btn-sm btn-danger" onclick="deleteFlow({{ flow.id }})">Delete</button>
                    {% if flow.trigger_type == 'webhook' %}
                    <span class="mono webhook-url" title="POST to this URL">/webhooks/trigger/{{ flow.id }}</span>
                    {% endif %}
                </div>
            </td>
        </tr>
    {% endfor %}
    </tbody>
</table>
{% else %}
<div class="notice">No automation flows yet. Create one above.</div>
{% endif %}
{% endif %}
{% endblock %}

{% block scripts %}
<script>
let steps = [];
let nextStepId = 1;
let cachedApps = [];

const REMOTE_COMMAND_OPTIONS = [
    'menu', 'top_menu', 'home', 'home_hold',
    'up', 'down', 'left', 'right', 'select',
    'play_pause', 'play', 'pause', 'stop', 'next', 'previous',
    'volume_up', 'volume_down'
];

function getEditingFlowId() {
    const raw = document.getElementById('editing-flow-id').value;
    const id = parseInt(raw, 10);
    return Number.isNaN(id) ? null : id;
}

function setEditingFlowId(idOrNull) {
    const hidden = document.getElementById('editing-flow-id');
    if (hidden) hidden.value = idOrNull == null ? '' : String(idOrNull);
}

function setEditMode(enabled) {
    const saveBtn = document.getElementById('save-flow-btn');
    const cancelBtn = document.getElementById('cancel-edit-btn');
    if (saveBtn) saveBtn.textContent = enabled ? 'Update Flow' : 'Save Flow';
    if (cancelBtn) cancelBtn.classList.toggle('hidden', !enabled);
}

function setBuilderStatus(message, isError = false) {
    const box = document.getElementById('flow-builder-status');
    if (!box) return;
    if (!message) {
        box.style.display = 'none';
        box.textContent = '';
        box.style.borderColor = '';
        box.style.color = '';
        return;
    }
    box.style.display = 'block';
    box.textContent = (isError ? '❌ ' : '✅ ') + message;
    if (isError) {
        box.style.borderColor = 'var(--danger)';
        box.style.color = 'var(--danger)';
    } else {
        box.style.borderColor = 'var(--success)';
        box.style.color = 'var(--success)';
    }
}

function stepTemplate(kind) {
    switch (kind) {
        case 'power_on':
            return { id: nextStepId++, type: 'power', payload: { turn_on: true } };
        case 'power_off':
            return { id: nextStepId++, type: 'power', payload: { turn_on: false } };
        case 'launch_app': {
            const bundleId = cachedApps.length > 0 ? (cachedApps[0].bundle_id || '') : '';
            return { id: nextStepId++, type: 'launch_app', payload: { bundle_id: bundleId } };
        }
        case 'remote_command':
            return { id: nextStepId++, type: 'remote_command', payload: { command: 'menu' } };
        case 'wait_seconds':
            return { id: nextStepId++, type: 'wait_seconds', payload: { seconds: 1 } };
        case 'swipe':
            return { id: nextStepId++, type: 'swipe', payload: { direction: 'up' } };
        default:
            return null;
    }
}

function addStep(kind) {
    const step = stepTemplate(kind);
    if (!step) return;
    steps.push(step);
    renderSteps();
}

function removeStep(stepId) {
    steps = steps.filter(s => s.id !== stepId);
    renderSteps();
}

function duplicateStep(stepId) {
    const src = steps.find(s => s.id === stepId);
    if (!src) return;
    const copy = {
        id: nextStepId++,
        type: src.type,
        payload: JSON.parse(JSON.stringify(src.payload || {})),
    };
    const idx = steps.findIndex(s => s.id === stepId);
    steps.splice(idx + 1, 0, copy);
    renderSteps();
}

function moveStep(fromIndex, toIndex) {
    if (fromIndex === toIndex || fromIndex < 0 || toIndex < 0) return;
    const [item] = steps.splice(fromIndex, 1);
    steps.splice(toIndex, 0, item);
    renderSteps();
}

function onPaletteDragStart(event) {
    event.dataTransfer.setData('text/action-kind', event.currentTarget.dataset.actionKind);
}

function onStepDragStart(event) {
    event.dataTransfer.setData('text/step-index', event.currentTarget.dataset.index);
}

function onStepDragOver(event) {
    event.preventDefault();
}

function onStepDrop(event) {
    event.preventDefault();
    const from = parseInt(event.dataTransfer.getData('text/step-index'), 10);
    const to = parseInt(event.currentTarget.dataset.index, 10);
    if (!Number.isNaN(from) && !Number.isNaN(to)) {
        moveStep(from, to);
    }
}

function onDropzoneDragOver(event) {
    event.preventDefault();
}

function onDropzoneDrop(event) {
    event.preventDefault();
    const kind = event.dataTransfer.getData('text/action-kind');
    if (kind) {
        addStep(kind);
    }
}

function renderLaunchAppEditor(step, index) {
    const options = cachedApps.map(a => {
        const selected = a.bundle_id === step.payload.bundle_id ? 'selected' : '';
        return `<option value="${escapeHtml(a.bundle_id || '')}" ${selected}>${escapeHtml(a.name || 'Unknown')} (${escapeHtml(a.bundle_id || '')})</option>`;
    }).join('');

    const hasApps = cachedApps.length > 0;
    return `
        <label>App
            <select ${hasApps ? '' : 'disabled'} data-step-index="${index}" onchange="onLaunchAppSelected(event)">
                ${hasApps ? options : '<option value="">No apps available from device</option>'}
            </select>
        </label>
        <label>Bundle ID
            <input type="text" value="${escapeHtml(step.payload.bundle_id || '')}" data-step-index="${index}" oninput="onLaunchBundleInput(event)" placeholder="com.netflix.Netflix" />
        </label>
    `;
}

function renderPowerEditor(step, index) {
    const turnOn = !!step.payload.turn_on;
    return `
        <label>Power Action
            <select data-step-index="${index}" onchange="onPowerSelect(event)">
                <option value="on" ${turnOn ? 'selected' : ''}>Power On</option>
                <option value="off" ${!turnOn ? 'selected' : ''}>Power Off</option>
            </select>
        </label>
    `;
}

function renderRemoteEditor(step, index) {
    const options = REMOTE_COMMAND_OPTIONS.map(cmd => {
        const selected = cmd === step.payload.command ? 'selected' : '';
        return `<option value="${cmd}" ${selected}>${cmd}</option>`;
    }).join('');
    return `
        <label>Command
            <select data-step-index="${index}" onchange="onRemoteCommandSelect(event)">
                ${options}
            </select>
        </label>
    `;
}

function renderWaitEditor(step, index) {
    const seconds = Number(step.payload.seconds ?? 1);
    return `
        <label>Seconds
            <input type="number" min="0" step="0.1" value="${Number.isFinite(seconds) ? seconds : 1}" data-step-index="${index}" oninput="onWaitSecondsInput(event)" />
        </label>
    `;
}

function renderSwipeEditor(step, index) {
    const SWIPE_DIRECTIONS = ['up', 'down', 'left', 'right'];
    const current = step.payload.direction || 'up';
    const options = SWIPE_DIRECTIONS.map(d =>
        `<option value="${d}" ${d === current ? 'selected' : ''}>${d.charAt(0).toUpperCase() + d.slice(1)}</option>`
    ).join('');
    return `
        <label>Direction
            <select data-step-index="${index}" onchange="onSwipeDirectionSelect(event)">
                ${options}
            </select>
        </label>
    `;
}

function renderSteps() {
    const container = document.getElementById('flow-steps');
    if (!container) return;

    if (steps.length === 0) {
        container.innerHTML = '<div class="notice">No steps yet. Drag an action from the palette to begin.</div>';
        return;
    }

    container.innerHTML = steps.map((step, index) => {
        let editor = '';
        if (step.type === 'launch_app') editor = renderLaunchAppEditor(step, index);
        if (step.type === 'power') editor = renderPowerEditor(step, index);
        if (step.type === 'remote_command') editor = renderRemoteEditor(step, index);
        if (step.type === 'wait_seconds') editor = renderWaitEditor(step, index);
        if (step.type === 'swipe') editor = renderSwipeEditor(step, index);

        return `
            <div class="sequence-step" draggable="true" data-index="${index}" ondragstart="onStepDragStart(event)" ondragover="onStepDragOver(event)" ondrop="onStepDrop(event)">
                <div class="sequence-step-header">
                    <strong>Step ${index + 1}: ${escapeHtml(step.type)}</strong>
                    <div class="controls-button-row">
                        <button type="button" class="btn btn-sm btn-secondary" onclick="duplicateStep(${step.id})">Duplicate</button>
                        <button type="button" class="btn btn-sm btn-danger" onclick="removeStep(${step.id})">Remove</button>
                    </div>
                </div>
                <div class="form" style="margin-top:0.5rem;">
                    ${editor}
                </div>
            </div>
        `;
    }).join('');
}

function onPowerSelect(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.turn_on = event.currentTarget.value === 'on';
}

function onRemoteCommandSelect(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.command = event.currentTarget.value;
}

function onWaitSecondsInput(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    const value = parseFloat(event.currentTarget.value);
    steps[idx].payload.seconds = Number.isNaN(value) ? 0 : Math.max(0, value);
}

function onSwipeDirectionSelect(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.direction = event.currentTarget.value;
}

function onLaunchAppSelected(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.bundle_id = event.currentTarget.value;
    renderSteps();
}

function onLaunchBundleInput(event) {
    const idx = parseInt(event.currentTarget.dataset.stepIndex, 10);
    if (Number.isNaN(idx) || !steps[idx]) return;
    steps[idx].payload.bundle_id = event.currentTarget.value.trim();
}

async function loadAppsForDevice(showStatus = false) {
    const deviceId = parseInt(document.getElementById('flow-device-id').value, 10);
    if (Number.isNaN(deviceId)) return;
    try {
        const res = await fetch(`/apps/list/${deviceId}`);
        const data = await res.json();
        if (!res.ok) {
            cachedApps = [];
            renderSteps();
            if (showStatus) {
                setBuilderStatus(data.detail || 'Could not load apps from device', true);
            }
            return;
        }

        cachedApps = Array.isArray(data) ? data : [];
        if (showStatus) {
            setBuilderStatus(`Loaded ${cachedApps.length} app(s) for selected device.`, false);
        }
        renderSteps();
    } catch (err) {
        cachedApps = [];
        renderSteps();
        if (showStatus) {
            setBuilderStatus(String(err), true);
        }
    }
}

async function onDeviceChanged() {
    await loadAppsForDevice(true);
}

function resetBuilderForNewFlow() {
    setEditingFlowId(null);
    setEditMode(false);
    steps = [];
    renderSteps();
}

function cancelEditMode() {
    resetBuilderForNewFlow();
    setBuilderStatus('Edit canceled. Creating new flow.', false);
}

function flowToSteps(flow) {
    let payload = {};
    try {
        payload = JSON.parse(flow.action_payload || '{}');
    } catch {
        payload = {};
    }

    if (flow.action_type === 'sequence' && Array.isArray(payload.actions)) {
        return payload.actions
            .filter(a => a && typeof a === 'object')
            .map(a => ({
                id: nextStepId++,
                type: String(a.type || a.action_type || ''),
                payload: (a.payload && typeof a.payload === 'object') ? a.payload : {},
            }))
            .filter(s => !!s.type);
    }

    // Backward compatibility: load legacy single-action flow as one visual step.
    return [{
        id: nextStepId++,
        type: String(flow.action_type || 'remote_command'),
        payload: payload && typeof payload === 'object' ? payload : {},
    }];
}

async function editFlow(flowId) {
    try {
        const res = await fetch(`/automations/${flowId}`);
        const flow = await res.json();
        if (!res.ok) {
            setBuilderStatus(flow.detail || 'Failed to load flow for editing.', true);
            return;
        }

        document.getElementById('flow-name').value = flow.name || '';
        document.getElementById('flow-device-id').value = String(flow.device_id);
        document.getElementById('flow-trigger-type').value = flow.trigger_type || 'manual';

        await loadAppsForDevice(false);

        steps = flowToSteps(flow);
        renderSteps();
        setEditingFlowId(flowId);
        setEditMode(true);
        setBuilderStatus(`Editing flow: ${flow.name}`, false);

        // Scroll to top so editor is visible immediately
        window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
        setBuilderStatus(String(err), true);
    }
}

async function createFlow(e) {
    e.preventDefault();

    if (steps.length === 0) {
        setBuilderStatus('Add at least one step to the sequence.', true);
        return;
    }

    const sequencePayload = {
        actions: steps.map(step => ({
            type: step.type,
            payload: step.payload,
        }))
    };

    const editingId = getEditingFlowId();
    const endpoint = editingId ? `/automations/${editingId}` : '/automations/';
    const method = editingId ? 'PUT' : 'POST';

    const res = await fetch(endpoint, {
        method,
        headers: {'Content-Type':'application/json'},
        body: JSON.stringify({
            name: document.getElementById('flow-name').value,
            device_id: parseInt(document.getElementById('flow-device-id').value),
            trigger_type: document.getElementById('flow-trigger-type').value,
            trigger_payload: '{}',
            action_type: 'sequence',
            action_payload: JSON.stringify(sequencePayload),
        })
    });

    if (res.ok) {
        location.reload();
    } else {
        const data = await res.json().catch(() => ({}));
        setBuilderStatus(data.detail || `Failed to ${editingId ? 'update' : 'create'} automation flow.`, true);
    }
}

document.addEventListener('DOMContentLoaded', () => {
    setEditMode(false);
    renderSteps();
    loadAppsForDevice(false);
});

async function runFlow(id) {
    const res = await fetch(`/automations/${id}/run`, { method: 'POST' });
    const data = await res.json();
    alert(res.ok ? '✅ Flow triggered: ' + JSON.stringify(data.action || data) : '❌ ' + (data.detail || 'Error'));
}

async function deleteFlow(id) {
    if (!confirm('Delete this flow?')) return;
    await fetch(`/automations/${id}`, { method: 'DELETE' });
    location.reload();
}

function escapeHtml(value) {
    return String(value)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Devices · Home Automation Server{% endblock %}

{% block content %}
<div class="page-header">
    <h1>Apple TV Devices</h1>
    <button class="btn btn-primary" onclick="scanDevices()"> Scan Network</button>
</div>

<!-- Scan results (populated by JS) -->
<div id="scan-results" class="hidden">
    <div class="page-header" style="margin-top: 1rem;">
        <h2>Discovered Devices</h2>
        <div>
            <button class="btn btn-sm btn-secondary" onclick="selectAllScanned(true)">Select All</button>
            <button class="btn btn-sm btn-secondary" onclick="selectAllScanned(false)">Clear</button>
            <button class="btn btn-sm btn-success" onclick="saveSelectedScanned()">Save Selected</button>
        </div>
    </div>
    <div id="scan-summary" class="notice hidden"></div>
    <div id="scan-list"></div>
</div>

<!-- Saved devices -->
<h2>Saved Devices</h2>
{% if devices %}
<table class="data-table">
    <thead>
        <tr>
            <th>Name</th>
            <th>Identifier</th>
            <th>IP Address</th>
            <th>Pairing</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
    {% for device in devices %}
        {% set protocols = pairing_protocols.get(device.id, []) %}
        <tr>
            <td>{{ device.name }}</td>
            <td class="mono truncate">{{ device.identifier }}</td>
            <td class="mono">{{ device.ip_address }}</td>
            <td>
                {% if protocols %}
                    {% for proto in protocols %}
                        <span class="badge badge-action">{{ proto }}</span>
                    {% endfor %}
                {% else %}
                    <span class="badge" style="border-color:#f87171;color:#f87171;">Not paired</span>
                {% endif %}
            </td>
            <td style="display:flex;gap:0.4rem;flex-wrap:wrap;">
                <a href="/ui/pairing?device_id={{ device.id }}" class="btn btn-sm btn-primary">
                    {% if protocols %} Re-pair{% else %} Pair{% endif %}
                </a>
                <button class="btn btn-sm btn-danger" onclick="deleteDevice({{ device.id }})">Delete</button>
            </td>
        </tr>
    {% endfor %}
    </tbody>
</table>
{% else %}
<div class="notice">No devices saved. Use the Scan button to discover Apple TVs on your network.</div>
{% endif %}

<!-- Add device manually -->
<details class="collapsible">
    <summary>➕ Add device manually</summary>
    <form class="form" onsubmit="addDevice(event)">
        <label>Name <input type="text" id="dev-name" required placeholder="Living Room Apple TV" /></label>
        <label>Identifier <input type="text" id="dev-identifier" required placeholder="AA:BB:CC:DD:EE:FF" /></label>
        <label>IP Address <input type="text" id="dev-ip" required placeholder="192.168.1.100" /></label>
        <button type="submit" class="btn btn-primary">Save Device</button>
    </form>
</details>
{% endblock %}

{% block scripts %}
<script>
let lastScanned = [];

async function scanDevices() {
    const btn = document.querySelector('button[onclick="scanDevices()"]');
    btn.textContent = '⏳ Scanning…';
    btn.disabled = true;
    try {
        const [scanRes, savedRes] = await Promise.all([
            fetch('/devices/scan', { method: 'POST' }),
            fetch('/devices/')
        ]);
        const data = await scanRes.json();
        const saved = await savedRes.json();
        const savedByIdentifier = new Set(saved.map(d => d.identifier));

        lastScanned = data.map(d => ({
            ...d,
            alreadySaved: savedByIdentifier.has(d.identifier)
        }));

        const list = document.getElementById('scan-list');
        const summary = document.getElementById('scan-summary');
        list.innerHTML = '';
        if (lastScanned.length === 0) {
            list.innerHTML = '<p class="notice">No devices found.</p>';
            summary.classList.add('hidden');
        } else {
            const existingCount = lastScanned.filter(d => d.alreadySaved).length;
            summary.textContent = `${lastScanned.length} discovered · ${existingCount} already saved`;
            summary.classList.remove('hidden');

            lastScanned.forEach((d, idx) => {
                const badge = d.alreadySaved
                    ? '<span class="badge" style="border-color:#34d399;color:#34d399;">Already saved</span>'
                    : '<span class="badge" style="border-color:#7c6af7;color:#7c6af7;">New</span>';
                list.innerHTML += `
                <div class="scan-card">
                    <input type="checkbox" class="scan-check" data-index="${idx}" ${d.alreadySaved ? '' : 'checked'} ${d.alreadySaved ? 'disabled' : ''} />
                    <strong>${d.name}</strong> · ${d.model} (${d.os_version})<br/>
                    <span class="mono">${d.identifier}</span> · ${d.ip_address}
                    ${badge}
                    <button class="btn btn-sm btn-success" ${d.alreadySaved ? 'disabled' : ''} onclick='saveScanned(${JSON.stringify(d)})'>Save</button>
                </div>`;
            });
        }
        document.getElementById('scan-results').classList.remove('hidden');
    } catch(e) {
        alert('Scan failed: ' + e);
    } finally {
        btn.textContent = ' Scan Network';
        btn.disabled = false;
    }
}

function selectAllScanned(selectAll) {
    document.querySelectorAll('.scan-check').forEach(cb => {
        if (!cb.disabled) cb.checked = selectAll;
    });
}

async function saveSelectedScanned() {
    const selected = Array.from(document.querySelectorAll('.scan-check:checked'))
        .filter(cb => !cb.disabled)
        .map(cb => lastScanned[parseInt(cb.dataset.index, 10)])
        .filter(Boolean)
        .map(d => ({ name: d.name, identifier: d.identifier, ip_address: d.ip_address }));

    if (selected.length === 0) {
        alert('No new devices selected.');
        return;
    }

    const res = await fetch('/devices/batch', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ devices: selected })
    });
    const data = await res.json();
    if (!res.ok) {
        alert('Batch save failed: ' + (data.detail || 'unknown error'));
        return;
    }
    alert(`Saved ${data.added_count} device(s), skipped ${data.skipped_count}.`);
    location.reload();
}

async function saveScanned(d) {
    await fetch('/devices/', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ name: d.name, identifier: d.identifier, ip_address: d.ip_address })
    });
    location.reload();
}

async function addDevice(e) {
    e.preventDefault();
    await fetch('/devices/', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            name: document.getElementById('dev-name').value,
            identifier: document.getElementById('dev-identifier').value,
            ip_address: document.getElementById('dev-ip').value,
        })
    });
    location.reload();
}

async function deleteDevice(id) {
    if (!confirm('Delete this device?')) return;
    await fetch(`/devices/${id}`, { method: 'DELETE' });
    location.reload();
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Devices · Home Automation Server{% endblock %}

{% block content %}
<div class="page-header">
    <h1>Apple TV Devices</h1>
    <button class="btn btn-primary" onclick="scanDevices()"> Scan Network</button>
</div>

<!-- Scan results (populated by JS) -->
<div id="scan-results" class="hidden">
    <div class="page-header" style="margin-top: 1rem;">
        <h2>Discovered Devices</h2>
        <div>
            <button class="btn btn-sm btn-secondary" onclick="selectAllScanned(true)">Select All</button>
            <button class="btn btn-sm btn-secondary" onclick="selectAllScanned(false)">Clear</button>
            <button class="btn btn-sm btn-success" onclick="saveSelectedScanned()">Save Selected</button>
        </div>
    </div>
    <div id="scan-summary" class="notice hidden"></div>
    <div id="scan-list"></div>
</div>

<!-- Saved devices -->
<h2>Saved Devices</h2>
{% if devices %}
<!-- Desktop Table View -->
<table class="data-table data-table-desktop">
    <thead>
        <tr>
            <th>Name</th>
            <th>Identifier</th>
            <th>IP Address</th>
            <th>Pairing</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
    {% for device in devices %}
        {% set protocols = pairing_protocols.get(device.id, []) %}
        <tr>
            <td>{{ device.name }}</td>
            <td class="mono truncate">{{ device.identifier }}</td>
            <td class="mono">{{ device.ip_address }}</td>
            <td>
                {% if protocols %}
                    {% for proto in protocols %}
                        <span class="badge badge-action">{{ proto }}</span>
                    {% endfor %}
                {% else %}
                    <span class="badge" style="border-color:#f87171;color:#f87171;">Not paired</span>
                {% endif %}
            </td>
            <td style="display:flex;gap:0.4rem;flex-wrap:wrap;">
                <a href="/ui/pairing?device_id={{ device.id }}" class="btn btn-sm btn-primary">
                    {% if protocols %} Re-pair{% else %} Pair{% endif %}
                </a>
                <button class="btn btn-sm btn-danger" onclick="deleteDevice({{ device.id }})">Delete</button>
            </td>
        </tr>
    {% endfor %}
    </tbody>
</table>

<!-- Mobile Card View -->
<div class="devices-card-grid">
    {% for device in devices %}
        {% set protocols = pairing_protocols.get(device.id, []) %}
        <div class="device-card">
            <div class="device-card-header">
                <h3>{{ device.name }}</h3>
            </div>
            <div class="device-card-body">
                <div class="device-info-row">
                    <span class="device-label">Identifier:</span>
                    <span class="device-value mono">{{ device.identifier }}</span>
                </div>
                <div class="device-info-row">
                    <span class="device-label">IP:</span>
                    <span class="device-value mono">{{ device.ip_address }}</span>
                </div>
                <div class="device-info-row">
                    <span class="device-label">Pairing:</span>
                    <div class="device-badges">
                        {% if protocols %}
                            {% for proto in protocols %}
                                <span class="badge badge-action">{{ proto }}</span>
                            {% endfor %}
                        {% else %}
                            <span class="badge" style="border-color:#f87171;color:#f87171;">Not paired</span>
                        {% endif %}
                    </div>
                </div>
            </div>
            <div class="device-card-actions">
                <a href="/ui/pairing?device_id={{ device.id }}" class="btn btn-sm btn-primary">
                    {% if protocols %} Re-pair{% else %} Pair{% endif %}
                </a>
                <button class="btn btn-sm btn-danger" onclick="deleteDevice({{ device.id }})">Delete</button>
            </div>
        </div>
    {% endfor %}
</div>
{% else %}
<div class="notice">No devices saved. Use the Scan button to discover Apple TVs on your network.</div>
{% endif %}

<!-- Add device manually -->
<details class="collapsible">
    <summary>➕ Add device manually</summary>
    <form class="form" onsubmit="addDevice(event)">
        <label>Name <input type="text" id="dev-name" required placeholder="Living Room Apple TV" /></label>
        <label>Identifier <input type="text" id="dev-identifier" required placeholder="AA:BB:CC:DD:EE:FF" /></label>
        <label>IP Address <input type="text" id="dev-ip" required placeholder="192.168.1.100" /></label>
        <button type="submit" class="btn btn-primary">Save Device</button>
    </form>
</details>
{% endblock %}

{% block scripts %}
<script>
let lastScanned = [];

async function scanDevices() {
    const btn = document.querySelector('button[onclick="scanDevices()"]');
    btn.textContent = '⏳ Scanning…';
    btn.disabled = true;
    try {
        const [scanRes, savedRes] = await Promise.all([
            fetch('/devices/scan', { method: 'POST' }),
            fetch('/devices/')
        ]);
        const data = await scanRes.json();
        const saved = await savedRes.json();
        const savedByIdentifier = new Set(saved.map(d => d.identifier));

        lastScanned = data.map(d => ({
            ...d,
            alreadySaved: savedByIdentifier.has(d.identifier)
        }));

        const list = document.getElementById('scan-list');
        const summary = document.getElementById('scan-summary');
        list.innerHTML = '';
        if (lastScanned.length === 0) {
            list.innerHTML = '<p class="notice">No devices found.</p>';
            summary.classList.add('hidden');
        } else {
            const existingCount = lastScanned.filter(d => d.alreadySaved).length;
            summary.textContent = `${lastScanned.length} discovered · ${existingCount} already saved`;
            summary.classList.remove('hidden');

            lastScanned.forEach((d, idx) => {
                const badge = d.alreadySaved
                    ? '<span class="badge" style="border-color:#34d399;color:#34d399;">Already saved</span>'
                    : '<span class="badge" style="border-color:#7c6af7;color:#7c6af7;">New</span>';
                list.innerHTML += `
                <div class="scan-card">
                    <input type="checkbox" class="scan-check" data-index="${idx}" ${d.alreadySaved ? '' : 'checked'} ${d.alreadySaved ? 'disabled' : ''} />
                    <strong>${d.name}</strong> · ${d.model} (${d.os_version})<br/>
                    <span class="mono">${d.identifier}</span> · ${d.ip_address}
                    ${badge}
                    <button class="btn btn-sm btn-success" ${d.alreadySaved ? 'disabled' : ''} onclick='saveScanned(${JSON.stringify(d)})'>Save</button>
                </div>`;
            });
        }
        document.getElementById('scan-results').classList.remove('hidden');
    } catch(e) {
        alert('Scan failed: ' + e);
    } finally {
        btn.textContent = ' Scan Network';
        btn.disabled = false;
    }
}

function selectAllScanned(selectAll) {
    document.querySelectorAll('.scan-check').forEach(cb => {
        if (!cb.disabled) cb.checked = selectAll;
    });
}

async function saveSelectedScanned() {
    const selected = Array.from(document.querySelectorAll('.scan-check:checked'))
        .filter(cb => !cb.disabled)
        .map(cb => lastScanned[parseInt(cb.dataset.index, 10)])
        .filter(Boolean)
        .map(d => ({ name: d.name, identifier: d.identifier, ip_address: d.ip_address }));

    if (selected.length === 0) {
        alert('No new devices selected.');
        return;
    }

    const res = await fetch('/devices/batch', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ devices: selected })
    });
    const data = await res.json();
    if (!res.ok) {
        alert('Batch save failed: ' + (data.detail || 'unknown error'));
        return;
    }
    alert(`Saved ${data.added_count} device(s), skipped ${data.skipped_count}.`);
    location.reload();
}

async function saveScanned(d) {
    await fetch('/devices/', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ name: d.name, identifier: d.identifier, ip_address: d.ip_address })
    });
    location.reload();
}

async function addDevice(e) {
    e.preventDefault();
    await fetch('/devices/', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            name: document.getElementById('dev-name').value,
            identifier: document.getElementById('dev-identifier').value,
            ip_address: document.getElementById('dev-ip').value,
        })
    });
    location.reload();
}

async function deleteDevice(id) {
    if (!confirm('Delete this device?')) return;
    await fetch(`/devices/${id}`, { method: 'DELETE' });
    location.reload();
}
</script>
{% endblock %}

""" Automation engine – executes AutomationFlow actions. """
from __future__ import annotations
import asyncio import json import logging from typing import Any
from sqlmodel import Session, select
from home_automation_server.models.models import AutomationFlow, AppleTVDevice, AppleTVPairing from home_automation_server.services import pyatv_service
logger = logging.getLogger(__name__)
def _build_credentials(pairings: list[AppleTVPairing]) -> dict[str, str]: return {p.protocol: p.credentials for p in pairings}
async def _execute_single_action( *, device: AppleTVDevice, credentials: dict[str, str], action_type: str, action_payload: dict[str, Any], ) -> dict[str, Any]: """Execute one action and return a result payload.""" match action_type: case "wait_seconds": seconds = action_payload.get("seconds", 1) try: delay = float(seconds) except (TypeError, ValueError) as exc: raise ValueError("action_payload.seconds must be a number for wait_seconds action.") from exc
if delay < 0: raise ValueError("action_payload.seconds must be >= 0 for wait_seconds action.")
await asyncio.sleep(delay) return {"status": "ok", "action": "wait_seconds", "seconds": delay}
case "launch_app": bundle_id = action_payload.get("bundle_id") if not bundle_id: raise ValueError("action_payload must contain 'bundle_id' for launch_app action.") await pyatv_service.launch_app( device.identifier, device.ip_address, credentials, bundle_id ) return {"status": "ok", "action": "launch_app", "bundle_id": bundle_id}
case "remote_command": command = action_payload.get("command") if not command: raise ValueError("action_payload must contain 'command' for remote_command action.") await pyatv_service.send_remote_command( device.identifier, device.ip_address, credentials, command ) return {"status": "ok", "action": "remote_command", "command": command}
case "power": turn_on = action_payload.get("turn_on", True) await pyatv_service.power_toggle( device.identifier, device.ip_address, credentials, bool(turn_on) ) return {"status": "ok", "action": "power", "turn_on": turn_on}
case _: raise ValueError(f"Unknown action_type: {action_type}")
async def execute_flow(flow_id: int, session: Session) -> dict: """ Look up an AutomationFlow by ID and execute its action. Returns a result dict with status information. """ flow = session.get(AutomationFlow, flow_id) if flow is None: raise ValueError(f"AutomationFlow {flow_id} not found.")
device = session.get(AppleTVDevice, flow.device_id) if device is None: raise ValueError(f"Device {flow.device_id} not found.")
pairings = session.exec( select(AppleTVPairing).where(AppleTVPairing.device_id == device.id) ).all() credentials = _build_credentials(pairings)
action_payload: dict[str, Any] = json.loads(flow.action_payload or "{}") logger.info( "Executing flow '%s' (action=%s) on device '%s'", flow.name, flow.action_type, device.name, )
if flow.action_type == "sequence": # Expected payload shape: # { # "actions": [ # {"type": "power", "payload": {"turn_on": true}}, # {"type": "launch_app", "payload": {"bundle_id": "com.netflix.Netflix"}} # ] # } actions = action_payload.get("actions") if not isinstance(actions, list) or not actions: raise ValueError("action_payload must contain a non-empty 'actions' list for sequence action.")
results: list[dict[str, Any]] = [] for index, item in enumerate(actions, start=1): if not isinstance(item, dict): raise ValueError(f"actions[{index}] must be an object.")
sub_type = item.get("type") or item.get("action_type") sub_payload = item.get("payload") if sub_payload is None: sub_payload = item.get("action_payload", {})
if not isinstance(sub_type, str) or not sub_type: raise ValueError(f"actions[{index}] must include 'type' (or 'action_type').") if not isinstance(sub_payload, dict): raise ValueError(f"actions[{index}] payload must be an object.")
result = await _execute_single_action( device=device, credentials=credentials, action_type=sub_type, action_payload=sub_payload, ) results.append({"step": index, **result})
return { "status": "ok", "action": "sequence", "steps": len(results), "results": results, }
return await _execute_single_action( device=device, credentials=credentials, action_type=flow.action_type, action_payload=action_payload, )

""" Automation engine – executes AutomationFlow actions. """
from __future__ import annotations
import asyncio import json import logging from typing import Any
from sqlmodel import Session, select
from home_automation_server.models.models import AutomationFlow, AppleTVDevice, AppleTVPairing from home_automation_server.services import pyatv_service
logger = logging.getLogger(__name__)
def _build_credentials(pairings: list[AppleTVPairing]) -> dict[str, str]: return {p.protocol: p.credentials for p in pairings}
async def _execute_single_action( *, device: AppleTVDevice, credentials: dict[str, str], action_type: str, action_payload: dict[str, Any], ) -> dict[str, Any]: """Execute one action and return a result payload.""" match action_type: case "wait_seconds": seconds = action_payload.get("seconds", 1) try: delay = float(seconds) except (TypeError, ValueError) as exc: raise ValueError("action_payload.seconds must be a number for wait_seconds action.") from exc
if delay < 0: raise ValueError("action_payload.seconds must be >= 0 for wait_seconds action.")
await asyncio.sleep(delay) return {"status": "ok", "action": "wait_seconds", "seconds": delay}
case "launch_app": bundle_id = action_payload.get("bundle_id") if not bundle_id: raise ValueError("action_payload must contain 'bundle_id' for launch_app action.") await pyatv_service.launch_app( device.identifier, device.ip_address, credentials, bundle_id ) return {"status": "ok", "action": "launch_app", "bundle_id": bundle_id}
case "remote_command": command = action_payload.get("command") if not command: raise ValueError("action_payload must contain 'command' for remote_command action.") await pyatv_service.send_remote_command( device.identifier, device.ip_address, credentials, command ) return {"status": "ok", "action": "remote_command", "command": command}
case "power": turn_on = action_payload.get("turn_on", True) await pyatv_service.power_toggle( device.identifier, device.ip_address, credentials, bool(turn_on) ) return {"status": "ok", "action": "power", "turn_on": turn_on}
case "swipe": direction = action_payload.get("direction") start_x = action_payload.get("start_x") start_y = action_payload.get("start_y") end_x = action_payload.get("end_x") end_y = action_payload.get("end_y") duration_ms = action_payload.get("duration_ms", 300)
if not direction and None in (start_x, start_y, end_x, end_y): raise ValueError( "action_payload must contain either 'direction' or all of " "'start_x', 'start_y', 'end_x', 'end_y' for swipe action." )
await pyatv_service.swipe_gesture( device.identifier, device.ip_address, credentials, direction=direction, start_x=start_x, start_y=start_y, end_x=end_x, end_y=end_y, duration_ms=int(duration_ms), ) result: dict[str, Any] = {"status": "ok", "action": "swipe", "duration_ms": duration_ms} if direction: result["direction"] = direction else: result.update({"start_x": start_x, "start_y": start_y, "end_x": end_x, "end_y": end_y}) return result
case _: raise ValueError(f"Unknown action_type: {action_type}")
async def execute_flow(flow_id: int, session: Session) -> dict: """ Look up an AutomationFlow by ID and execute its action. Returns a result dict with status information. """ flow = session.get(AutomationFlow, flow_id) if flow is None: raise ValueError(f"AutomationFlow {flow_id} not found.")
device = session.get(AppleTVDevice, flow.device_id) if device is None: raise ValueError(f"Device {flow.device_id} not found.")
pairings = session.exec( select(AppleTVPairing).where(AppleTVPairing.device_id == device.id) ).all() credentials = _build_credentials(pairings)
action_payload: dict[str, Any] = json.loads(flow.action_payload or "{}") logger.info( "Executing flow '%s' (action=%s) on device '%s'", flow.name, flow.action_type, device.name, )
if flow.action_type == "sequence": # Expected payload shape: # { # "actions": [ # {"type": "power", "payload": {"turn_on": true}}, # {"type": "launch_app", "payload": {"bundle_id": "com.netflix.Netflix"}} # ] # } actions = action_payload.get("actions") if not isinstance(actions, list) or not actions: raise ValueError("action_payload must contain a non-empty 'actions' list for sequence action.")
results: list[dict[str, Any]] = [] for index, item in enumerate(actions, start=1): if not isinstance(item, dict): raise ValueError(f"actions[{index}] must be an object.")
sub_type = item.get("type") or item.get("action_type") sub_payload = item.get("payload") if sub_payload is None: sub_payload = item.get("action_payload", {})
if not isinstance(sub_type, str) or not sub_type: raise ValueError(f"actions[{index}] must include 'type' (or 'action_type').") if not isinstance(sub_payload, dict): raise ValueError(f"actions[{index}] payload must be an object.")
result = await _execute_single_action( device=device, credentials=credentials, action_type=sub_type, action_payload=sub_payload, ) results.append({"step": index, **result})
return { "status": "ok", "action": "sequence", "steps": len(results), "results": results, }
return await _execute_single_action( device=device, credentials=credentials, action_type=flow.action_type, action_payload=action_payload, )
